    let ext = caps.get(1).unwrap().as_str();
    let file = caps.get(2).unwrap().as_str();
    let structure = caps.get(3).unwrap().as_str();
    let ids = caps.get(4).unwrap().as_str();

    let root = match ensure_fixture_dir() {
        Ok(r) => r,
